package com.socialblog.interaction.application;import com.fasterxml.jackson.databind.ObjectMapper;import com.socialblog.interaction.domain.*;import com.socialblog.interaction.repository.*;import org.junit.jupiter.api.Test;import java.util.*;import static org.mockito.Mockito.*;
class TargetEventConsumerTest{@Test void projectsAndDeduplicatesArticleEvent()throws Exception{TargetProjectionRepository targets=mock(TargetProjectionRepository.class);ProcessedEventRepository processed=mock(ProcessedEventRepository.class);UUID event=UUID.randomUUID(),article=UUID.randomUUID();when(processed.existsById(event)).thenReturn(false,true);when(targets.findById(new TargetKey(TargetType.ARTICLE,article))).thenReturn(Optional.empty());TargetEventConsumer c=new TargetEventConsumer(new ObjectMapper(),targets,processed);String raw="{\"eventId\":\""+event+"\",\"eventType\":\"ArticlePublished\",\"payload\":{\"articleId\":\""+article+"\"}}";c.consume(raw);c.consume(raw);verify(targets,times(1)).save(argThat(TargetProjection::isActive));verify(processed,times(1)).save(any());}}
